import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { Database } from '../../src/utils/database.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../../src/events/event-types.js';
import type { NotificationAdapter, NotificationPayload, NotificationResult } from '../../src/models/notification.js';

/**
 * Integration tests for the full notification pipeline:
 *   EventBus → NotificationService → Adapters (email/sms/webhook)
 *                                  → PreferencesService (filtering)
 *                                  → NotificationHistoryService (logging)
 */
describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailTransport: InMemoryTransport;
  let emailAdapter: EmailAdapter;
  let smsTransport: InMemorySmsTransport;
  let smsAdapter: SmsAdapter;
  let webhookTransport: InMemoryWebhookTransport;
  let webhookAdapter: WebhookAdapter;
  let preferencesRepo: PreferencesRepository;
  let preferencesService: PreferencesService;
  let historyRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    resetNotificationIdCounter();
    resetLogIdCounter();

    // Wire up the full pipeline
    notificationService = new NotificationService(eventBus);

    // Email adapter
    emailTransport = new InMemoryTransport();
    emailAdapter = new EmailAdapter({ transport: emailTransport });
    notificationService.registerAdapter(emailAdapter);

    // SMS adapter
    smsTransport = new InMemorySmsTransport();
    smsAdapter = new SmsAdapter({ transport: smsTransport });
    notificationService.registerAdapter(smsAdapter);

    // Webhook adapter
    webhookTransport = new InMemoryWebhookTransport();
    webhookAdapter = new WebhookAdapter({
      url: 'https://hooks.example.com/notify',
      transport: webhookTransport,
    });
    notificationService.registerAdapter(webhookAdapter);

    // Preferences
    preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);

    // History
    historyRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(historyRepo);
    notificationService.setHistoryService(historyService);
  });

  // -- Helpers --

  function makeUser(overrides?: Partial<{ id: string; name: string; email: string }>) {
    return {
      id: overrides?.id ?? 'user-1',
      name: overrides?.name ?? 'Alice',
      email: overrides?.email ?? 'alice@example.com',
      role: 'member' as const,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  function makeOrder(overrides?: Partial<{ id: string; userId: string }>) {
    return {
      id: overrides?.id ?? 'order-1',
      userId: overrides?.userId ?? 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending' as const,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  // -------------------------------------------------------
  // 1. Email notification delivery
  // -------------------------------------------------------
  describe('email notification delivery', () => {
    it('should deliver email notification end-to-end via EventBus order:created', async () => {
      const user = makeUser();
      const order = makeOrder();

      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order,
        user,
        timestamp: new Date(),
      });

      // Verify adapter received the email
      const emails = emailAdapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]!.to).toBe('alice@example.com');
      expect(emails[0]!.subject).toContain('Order Confirmation');

      // Verify transport received the email
      const transported = emailTransport.getSentEmails();
      expect(transported).toHaveLength(1);
      expect(transported[0]!.to).toBe('alice@example.com');

      // Verify notification result
      const results = notificationService.getResults();
      expect(results).toHaveLength(1);
      expect(results[0]!.success).toBe(true);
      expect(results[0]!.notification.channel).toBe('email');
    });

    it('should deliver welcome email on user:created', async () => {
      const user = makeUser();

      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user,
        timestamp: new Date(),
      });

      const emails = emailAdapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]!.subject).toContain('Welcome');
      expect(emails[0]!.htmlBody).toContain('TaskFlow Pro');
    });

    it('should deliver order status update email on order:status-changed', async () => {
      const order = makeOrder();

      await eventBus.emit<OrderStatusChangedEvent>({
        type: 'order:status-changed',
        order: { ...order, status: 'shipped' },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const results = notificationService.getResults();
      expect(results).toHaveLength(1);
      expect(results[0]!.notification.type).toBe('order-status-update');
      expect(results[0]!.notification.body).toContain('confirmed');
      expect(results[0]!.notification.body).toContain('shipped');
    });
  });

  // -------------------------------------------------------
  // 2. SMS notification delivery
  // -------------------------------------------------------
  describe('SMS notification delivery', () => {
    it('should deliver SMS notification to user with valid phone number', async () => {
      const result = await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+15551234567',
        subject: 'Order Confirmed',
        body: 'Your order has been placed.',
        metadata: { userId: 'user-1', orderId: 'order-1' },
      });

      expect(result.success).toBe(true);
      expect(result.notification.channel).toBe('sms');

      const messages = smsAdapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.to).toBe('+15551234567');
      expect(messages[0]!.body).toContain('Order Confirmed');

      const transported = smsTransport.getSentMessages();
      expect(transported).toHaveLength(1);
    });

    it('should fail SMS delivery with invalid phone number', async () => {
      const result = await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: 'not-a-phone',
        subject: 'Order Confirmed',
        body: 'Your order has been placed.',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });
  });

  // -------------------------------------------------------
  // 3. Webhook notification delivery
  // -------------------------------------------------------
  describe('webhook notification delivery', () => {
    it('should deliver webhook notification with JSON payload', async () => {
      const result = await notificationService.send({
        type: 'order-status-update',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Order Shipped',
        body: 'Your order has shipped.',
        metadata: { userId: 'user-1', orderId: 'order-1' },
      });

      expect(result.success).toBe(true);
      expect(result.notification.channel).toBe('webhook');

      const requests = webhookAdapter.getSentRequests();
      expect(requests).toHaveLength(1);
      expect(requests[0]!.url).toBe('https://hooks.example.com/notify');

      const body = JSON.parse(requests[0]!.body);
      expect(body.type).toBe('order-status-update');
      expect(body.subject).toBe('Order Shipped');
      expect(body.metadata.orderId).toBe('order-1');

      const transported = webhookTransport.getSentRequests();
      expect(transported).toHaveLength(1);
    });

    it('should include webhook secret header when configured', async () => {
      // Re-create webhook adapter with secret
      const secretTransport = new InMemoryWebhookTransport();
      const secretWebhookAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com/secure',
        secret: 'my-secret-token',
        transport: secretTransport,
      });
      notificationService.registerAdapter(secretWebhookAdapter);

      await notificationService.send({
        type: 'welcome',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/secure',
        subject: 'Welcome',
        body: 'Hello!',
        metadata: { userId: 'user-1' },
      });

      const requests = secretWebhookAdapter.getSentRequests();
      expect(requests).toHaveLength(1);
      expect(requests[0]!.headers['X-Webhook-Secret']).toBe('my-secret-token');
    });
  });

  // -------------------------------------------------------
  // 4. Notification history logging
  // -------------------------------------------------------
  describe('notification history logging', () => {
    it('should log delivered email notifications in history', async () => {
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.getCount()).toBe(1);

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('delivered');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.type).toBe('welcome');
    });

    it('should log delivered SMS notifications in history', async () => {
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+15551234567',
        subject: 'Confirmed',
        body: 'Order confirmed.',
        metadata: { userId: 'user-sms' },
      });

      const logs = historyService.getByRecipient('+15551234567');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('delivered');
      expect(logs[0]!.channel).toBe('sms');
    });

    it('should log delivered webhook notifications in history', async () => {
      await notificationService.send({
        type: 'order-status-update',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Update',
        body: 'Shipped.',
        metadata: { userId: 'user-wh' },
      });

      const logs = historyService.query({ channel: 'webhook' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('delivered');
    });

    it('should log failed notifications in history', async () => {
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: 'invalid-phone',
        subject: 'Fail',
        body: 'Will fail.',
      });

      const logs = historyService.query({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.error).toContain('Invalid phone number');
    });

    it('should log suppressed notifications in history', async () => {
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      await notificationService.send({
        type: 'welcome',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Welcome',
        body: 'Hello!',
        metadata: { userId: 'user-1' },
      });

      const logs = historyService.query({ status: 'suppressed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.type).toBe('welcome');
    });

    it('should log multiple notifications across channels in history', async () => {
      // Send one on each channel
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Email',
        body: 'Via email.',
        metadata: { userId: 'user-2' },
      });
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+15559876543',
        subject: 'SMS',
        body: 'Via SMS.',
        metadata: { userId: 'user-2' },
      });
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Webhook',
        body: 'Via webhook.',
        metadata: { userId: 'user-2' },
      });

      expect(historyService.getCount()).toBe(3);

      expect(historyService.query({ channel: 'email' })).toHaveLength(1);
      expect(historyService.query({ channel: 'sms' })).toHaveLength(1);
      expect(historyService.query({ channel: 'webhook' })).toHaveLength(1);
    });
  });

  // -------------------------------------------------------
  // 5. User preferences filtering
  // -------------------------------------------------------
  describe('user preferences filtering', () => {
    it('should deliver email when email preferences are enabled', async () => {
      // Default preferences have all channels enabled
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Confirmed',
        body: 'Order placed.',
        metadata: { userId: 'user-1' },
      });

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      const results = notificationService.getResults();
      expect(results[0]!.success).toBe(true);
    });

    it('should suppress email when email is disabled for user', async () => {
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      await notificationService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Confirmed',
        body: 'Order placed.',
        metadata: { userId: 'user-1' },
      });

      // Email adapter should NOT have been called
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(emailTransport.getSentEmails()).toHaveLength(0);

      // But result is still recorded as success (suppressed)
      const results = notificationService.getResults();
      expect(results).toHaveLength(1);
      expect(results[0]!.success).toBe(true);
    });

    it('should suppress SMS when SMS is disabled for user', async () => {
      preferencesService.updateSmsPreferences('user-1', { enabled: false });

      await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+15551234567',
        subject: 'Confirmed',
        body: 'Order placed.',
        metadata: { userId: 'user-1' },
      });

      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(smsTransport.getSentMessages()).toHaveLength(0);
    });

    it('should suppress webhook when webhook is disabled for user', async () => {
      preferencesService.updateWebhookPreferences('user-1', { enabled: false });

      await notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Confirmed',
        body: 'Order placed.',
        metadata: { userId: 'user-1' },
