        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+15551234567',
        subject: 'SMS',
        body: 'Via sms.',
        metadata: { userId: 'user-1' },
      });

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
    });

    it('should allow all notifications for users with no stored preferences (opt-out model)', async () => {
      // user-new has no preferences at all
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'newuser@example.com',
        subject: 'Email',
        body: 'Test.',
        metadata: { userId: 'user-new' },
      });
