it('should handle a full user lifecycle: create user → place order → update status', async () => {
  const user = makeUser();
  const order = makeOrder();

  // Step 1: User created
  await eventBus.emit<UserCreatedEvent>({
    type: 'user:created',
    user,
    timestamp: new Date(),
  });

  // Step 2: Order created
  await eventBus.emit<OrderCreatedEvent>({
    type: 'order:created',
    order,
    user,
    timestamp: new Date(),
  });

  // Step 3: Order status changed
  // Note: The order:status-changed handler uses event.order.userId as the
  // email recipient. Since userId ('user-1') is not a valid email address,
  // the email adapter's recipient validation fails. This is a known
  // integration gap — OrderStatusChangedEvent doesn't carry user email.
  await eventBus.emit<OrderStatusChangedEvent>({
    type: 'order:status-changed',
    order: { ...order, status: 'shipped' },
    previousStatus: 'confirmed',
    newStatus: 'shipped',
    timestamp: new Date(),
  });

  // Should have 3 notification results total
  const results = notificationService.getResults();
  expect(results).toHaveLength(3);

  // First two succeed (valid email recipients), third fails (userId is not a valid email)
  expect(results[0]!.success).toBe(true);
  expect(results[1]!.success).toBe(true);
  expect(results[2]!.success).toBe(false);
  expect(results[2]!.error).toContain('Invalid');

  // Only 2 emails actually delivered (welcome + order-confirmation)
  expect(emailAdapter.getSentEmails()).toHaveLength(2);

  // All 3 logged in history (2 delivered + 1 failed)
  expect(historyService.getCount()).toBe(3);

  const delivered = historyService.query({ status: 'delivered' });
  expect(delivered).toHaveLength(2);

  const failed = historyService.query({ status: 'failed' });
  expect(failed).toHaveLength(1);
  expect(failed[0]!.type).toBe('order-status-update');
});

